#include <bits/stdc++.h>
using namespace std;

const int N=1e6+10;

struct Node{
    long long mn,c,sum,val,b,dp,nxt,res;
}t[N];

int n,p[N],a[N],head[N],h[N],son[N],tot;
long long ans;
char buf[1<<24];
vector<int> e[N];

inline void read() {
	scanf("%d%s", &n, buf);
	for (int i = 2, j = 0; i <= n; i++) {
		for (; ~buf[i + j - 2] & 1; j++);
		p[i] = j;
	}
	scanf("%s", buf);
	for (int i = 1, j = 0; i <= n; i++) {
		a[i] |= buf[j++] - 33 << 24;
		a[i] |= buf[j++] - 33 << 18;
		a[i] |= buf[j++] - 33 << 12;
		a[i] |= buf[j++] - 33 << 6;
		a[i] |= buf[j++] - 33;
	}
}

void cal(int x){
    t[x].val=max(0ll,t[x].mn-t[t[x].nxt].b);
    t[x].b=max(0ll,t[t[x].nxt].b-t[x].mn);
    t[x].dp=min(t[x].c,t[t[x].nxt].dp+1);
    t[x].res=t[x].sum-t[x].mn*t[x].c+t[x].b+t[x].dp*t[x].val+t[t[x].nxt].res;
}

void Merge(int x,int y){
    if(!y) return;
    Merge(t[x].nxt,t[y].nxt);
    t[x].mn=min(t[x].mn,t[y].mn);
    t[x].c+=t[y].c;
    t[x].sum+=t[y].sum;
    cal(x);
}

void dfs(int x){
    h[x]=1;
    for(int y:e[x]){
        dfs(y);
        h[x]=max(h[x],h[y]+1);
        if(h[y]>h[son[x]]) son[x]=y;
    }
    if(son[x]){
        int y=son[x],v=head[y];
        t[v].mn=a[y]-a[x];
        t[v].sum=a[y]-a[x];
        cal(v);
    }
    tot++;
    t[tot].nxt=head[son[x]];
    t[tot].mn=a[x];
    t[tot].c=1;
    t[tot].sum=a[x];
    cal(tot);
    head[x]=tot;
    for(int y:e[x])
        if(y!=son[x]){
            int v=head[y];
            t[v].mn=a[y]-a[x];
            t[v].sum=a[y]-a[x];
            cal(v);
            Merge(t[head[x]].nxt,v);
            cal(head[x]);
        }
    if(!t[head[x]].b){
        ans^=t[head[x]].res+1;
    }
}

int main(){
    read();
    for(int i=2;i<=n;i++)
        e[p[i]].push_back(i);
    dfs(1);
    printf("%lld",ans);
    return 0;
}
